  8â†’// ValidationError describes a single validation failure.
  9â†’type ValidationError struct {
 10â†’	Field   string `json:"field"`
 11â†’	Message string `json:"message"`
 12â†’}
 13â†’
 14â†’// Unexported interfaces let the validator access concrete-type metadata without
 15â†’// widening the public Field interface.
 16â†’type hasEnumOptions interface{ enumOptions() []EnumOption }
 17â†’type hasHardBounds interface{ hardBounds() (min, max *float64) }
 18â†’type hasMaxRadius interface{ maxRadiusKm() float64 }
 19â†’
 20â†’// ValidateRequest validates a SearchRequest against the registry.
 21â†’// All errors are collected (no short-circuit) and returned as a slice.
 22â†’// A nil/empty slice means the request is valid.
 23â†’//
 24â†’// The authenticated flag controls access to RESTRICTED fields: when false,
 25â†’// any filter on a RESTRICTED-searchability field produces a validation error.
 26â†’func ValidateRequest(reg *Registry, req SearchRequest, authenticated bool) []ValidationError {
 27â†’	var errs []ValidationError
 28â†’
 29â†’	for _, fi := range req.Filters {
 30â†’		field, ok := reg.Lookup(fi.Field)
 31â†’		if !ok {
 32â†’			errs = append(errs, ValidationError{Field: fi.Field, Message: "unknown field"})
 33â†’			continue
 34â†’		}
 35â†’
 36â†’		if !IsFieldSearchable(field.Descriptor(), authenticated) {
 37â†’			errs = append(errs, ValidationError{Field: fi.Field, Message: "field requires authentication"})
 38â†’			continue
 39â†’		}
 40â†’
 41â†’		switch field.Kind() {
 42â†’		case KindFullText:
 43â†’			var f FullTextFilter
 44â†’			if err := json.Unmarshal(fi.Value, &f); err != nil {
 45â†’				errs = append(errs, ValidationError{Field: fi.Field,
 46â†’					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
 47â†’				continue
 48â†’			}
 49â†’			if len(f.Query) > 512 {
 50â†’				errs = append(errs, ValidationError{Field: fi.Field,
 51â†’					Message: "value exceeds maximum length of 512 characters"})
 52â†’			}
 53â†’
 54â†’		case KindSubstring:
 55â†’			var f SubstringFilter
 56â†’			if err := json.Unmarshal(fi.Value, &f); err != nil {
 57â†’				errs = append(errs, ValidationError{Field: fi.Field,
 58â†’					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
 59â†’				continue
 60â†’			}
 61â†’			if len(f.Value) > 512 {
 62â†’				errs = append(errs, ValidationError{Field: fi.Field,
 63â†’					Message: "value exceeds maximum length of 512 characters"})
 64â†’			}
 65â†’
 66â†’		case KindExactString:
 67â†’			var f ExactStringFilter
 68â†’			if err := json.Unmarshal(fi.Value, &f); err != nil {
 69â†’				errs = append(errs, ValidationError{Field: fi.Field,
 70â†’					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
 71â†’				continue
 72â†’			}
 73â†’			if len(f.Value) > 512 {
 74â†’				errs = append(errs, ValidationError{Field: fi.Field,
 75â†’					Message: "value exceeds maximum length of 512 characters"})
 76â†’			}
 77â†’
 78â†’		case KindExactNumeric:
 79â†’			var f ExactNumericFilter
 80â†’			if err := json.Unmarshal(fi.Value, &f); err != nil {
 81â†’				errs = append(errs, ValidationError{Field: fi.Field,
 82â†’					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
 83â†’			}
 84â†’
 85â†’		case KindNumericRange:
 86â†’			var f NumericRangeFilter
 87â†’			if err := json.Unmarshal(fi.Value, &f); err != nil {
 88â†’				errs = append(errs, ValidationError{Field: fi.Field,
 89â†’					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
 90â†’				continue
 91â†’			}
 92â†’			if f.Min == nil && f.Max == nil {
 93â†’				errs = append(errs, ValidationError{Field: fi.Field,
 94â†’					Message: "at least one of min or max is required"})
 95â†’				break
 96â†’			}
 97â†’			if hb, ok := field.(hasHardBounds); ok {
 98â†’				hardMin, hardMax := hb.hardBounds()
 99â†’				if f.Min != nil && hardMin != nil && *f.Min < *hardMin {
100â†’					errs = append(errs, ValidationError{Field: fi.Field,
101â†’						Message: "value out of allowed range"})
102â†’				}
103â†’				if f.Max != nil && hardMax != nil && *f.Max > *hardMax {
104â†’					errs = append(errs, ValidationError{Field: fi.Field,
105â†’						Message: "value out of allowed range"})
106â†’				}
107â†’			}
108â†’
109â†’		case KindSingleEnum:
110â†’			var f SingleEnumFilter
111â†’			if err := json.Unmarshal(fi.Value, &f); err != nil {
112â†’				errs = append(errs, ValidationError{Field: fi.Field,
113â†’					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
114â†’				continue
115â†’			}
116â†’			if eo, ok := field.(hasEnumOptions); ok {
117â†’				opts := eo.enumOptions()
118â†’				if opts != nil && !containsOption(opts, f.Value) {
119â†’					errs = append(errs, ValidationError{Field: fi.Field,
120â†’						Message: fmt.Sprintf("value %q not in allowed options", f.Value)})
121â†’				}
122â†’			}
123â†’
124â†’		case KindMultiEnum:
125â†’			var f MultiEnumFilter
126â†’			if err := json.Unmarshal(fi.Value, &f); err != nil {
127â†’				errs = append(errs, ValidationError{Field: fi.Field,
128â†’					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
129â†’				continue
130â†’			}
131â†’			if len(f.Values) == 0 {
132â†’				errs = append(errs, ValidationError{Field: fi.Field,
133â†’					Message: "at least one value required"})
134â†’				break
135â†’			}
136â†’			if eo, ok := field.(hasEnumOptions); ok {
137â†’				opts := eo.enumOptions()
138â†’				if opts != nil {
139â†’					for _, v := range f.Values {
140â†’						if !containsOption(opts, v) {
141â†’							errs = append(errs, ValidationError{Field: fi.Field,
142â†’								Message: fmt.Sprintf("value %q not in allowed options", v)})
143â†’						}
144â†’					}
145â†’				}
146â†’			}
147â†’
148â†’		case KindGeo:
149â†’			var f GeoFilterInput
150â†’			if err := json.Unmarshal(fi.Value, &f); err != nil {
151â†’				errs = append(errs, ValidationError{Field: fi.Field,
152â†’					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
153â†’				continue
154â†’			}
155â†’			switch f.Kind {
156â†’			case GeoFilterKindRadius:
157â†’				if f.Radius == nil {
158â†’					errs = append(errs, ValidationError{Field: fi.Field,
159â†’						Message: "radius filter requires radius object"})
160â†’				} else {
161â†’					if f.Radius.RadiusKm <= 0 {
162â†’						errs = append(errs, ValidationError{Field: fi.Field,
163â†’							Message: "radius must be positive"})
164â†’					}
165â†’					if mr, ok := field.(hasMaxRadius); ok {
166â†’						if f.Radius.RadiusKm > mr.maxRadiusKm() {
167â†’							errs = append(errs, ValidationError{Field: fi.Field,
168â†’								Message: fmt.Sprintf("radius exceeds maximum of %g km", mr.maxRadiusKm())})
169â†’						}
170â†’					}
171â†’				}
172â†’			case GeoFilterKindBBox:
173â†’				if f.BBox == nil {
174â†’					errs = append(errs, ValidationError{Field: fi.Field,
175â†’						Message: "bbox filter requires bbox object"})
176â†’				}
177â†’			default:
178â†’				errs = append(errs, ValidationError{Field: fi.Field,
179â†’					Message: fmt.Sprintf("unknown geo filter kind: %q", f.Kind)})
180â†’			}
181â†’		}
182â†’	}
183â†’
184â†’	// Pagination checks use sentinel field names.
185â†’	if req.Limit > MaxLimit {
186â†’		errs = append(errs, ValidationError{Field: "_limit",
187â†’			Message: fmt.Sprintf("limit exceeds maximum of %d", MaxLimit)})
188â†’	}
189â†’	if req.Offset < 0 {
190â†’		errs = append(errs, ValidationError{Field: "_offset",
191â†’			Message: "offset must be non-negative"})
192â†’	}
193â†’
194â†’	// UserLocation validation.
195â†’	if loc := req.UserLocation; loc != nil {
196â†’		if loc.Latitude < -90 || loc.Latitude > 90 {
197â†’			errs = append(errs, ValidationError{Field: "_userLocation",
198â†’				Message: "latitude must be between -90 and 90"})
199â†’		}
200â†’		if loc.Longitude < -180 || loc.Longitude > 180 {
201â†’			errs = append(errs, ValidationError{Field: "_userLocation",
202â†’				Message: "longitude must be between -180 and 180"})
203â†’		}
204â†’		if loc.State != "" {
205â†’			if len(loc.State) != 2 || loc.State[0] < 'A' || loc.State[0] > 'Z' || loc.State[1] < 'A' || loc.State[1] > 'Z' {
206â†’				errs = append(errs, ValidationError{Field: "_userLocation",
207â†’					Message: "state must be a 2-letter uppercase code"})
208â†’			}
209â†’		}
210â†’	}
211â†’
212â†’	// Blend validation.
213â†’	if req.Blend != nil {
214â†’		hasNonZero := false
215â†’		for _, bw := range req.Blend.Weights {
216â†’			if _, ok := rankingProviderMap[bw.Field]; !ok {
217â†’				errs = append(errs, ValidationError{Field: "_blend",
218â†’					Message: fmt.Sprintf("unknown blend field %q", bw.Field)})
219â†’			}
220â†’			if bw.Weight < 0 || bw.Weight > 100 {
221â†’				errs = append(errs, ValidationError{Field: "_blend",
222â†’					Message: fmt.Sprintf("weight for %q must be 0â€“100", bw.Field)})
223â†’			}
224â†’			if bw.Weight > 0 {
225â†’				hasNonZero = true
226â†’			}
227â†’		}
228â†’		if !hasNonZero {
229â†’			errs = append(errs, ValidationError{Field: "_blend",
230â†’				Message: "at least one blend weight must be greater than 0"})
231â†’		}
232â†’	}
233â†’
234â†’	// Sort validation.
235â†’	if req.Sort != nil {
236â†’		switch req.Sort.Field {
237â†’		case "distance":
238â†’			if req.UserLocation == nil {
239â†’				errs = append(errs, ValidationError{Field: "_sort",
240â†’					Message: "sort by distance requires userLocation"})
241â†’			}
242â†’		case "name":
243â†’			// Always valid.
244â†’		case "blend_score":
245â†’			if req.Blend == nil {
246â†’				errs = append(errs, ValidationError{Field: "_sort",
247â†’					Message: "sort by blend_score requires an active ranking blend"})
248â†’			}
249â†’		default:
250â†’			f, ok := reg.Lookup(req.Sort.Field)
251â†’			if !ok {
252â†’				errs = append(errs, ValidationError{Field: "_sort",
253â†’					Message: fmt.Sprintf("unknown sort field %q", req.Sort.Field)})
254â†’			} else if !f.Descriptor().Sortable {
255â†’				errs = append(errs, ValidationError{Field: "_sort",
256â†’					Message: fmt.Sprintf("field %q is not sortable", req.Sort.Field)})
257â†’			}
258â†’		}
259â†’	}
260â†’
261â†’	return errs
262â†’}
