264â†’// containsOption returns true when opts contains an entry with Value == v.
265â†’func containsOption(opts []EnumOption, v string) bool {
266â†’	for _, o := range opts {
267â†’		if o.Value == v {
268â†’			return true
269â†’		}
270â†’	}
271â†’	return false
272â†’}
