10â†’// TestContractMatrix_Baseline validates all contract cases against
11â†’// ValidateRequest directly. This is the ground-truth reference that
12â†’// per-entry-point runners (handler, mcp) must agree with.
13â†’func TestContractMatrix_Baseline(t *testing.T) {
14â†’	t.Parallel()
15â†’	defaultReg := search.NewRegistry()
16â†’
17â†’	for _, cc := range search.ContractCases() {
18â†’		t.Run(cc.Name, func(t *testing.T) {
19â†’			t.Parallel()
20â†’
21â†’			reg := defaultReg
22â†’			if cc.Registry != nil {
23â†’				reg = cc.Registry
24â†’			}
25â†’
26â†’			errs := search.ValidateRequest(reg, cc.Request, cc.Authenticated)
27â†’
28â†’			if cc.WantValid {
29â†’				if len(errs) != 0 {
30â†’					t.Fatalf("expected valid request, got %d errors: %+v", len(errs), errs)
31â†’				}
32â†’				return
33â†’			}
34â†’
35â†’			// Expect at least one error matching the contract.
36â†’			if len(errs) == 0 {
37â†’				t.Fatal("expected validation errors, got none")
38â†’			}
39â†’
40â†’			found := false
41â†’			for _, e := range errs {
42â†’				if e.Field == cc.WantField && strings.Contains(e.Message, cc.WantContains) {
43â†’					found = true
44â†’					break
45â†’				}
46â†’			}
47â†’			if !found {
48â†’				t.Errorf("expected error field=%q containing %q, got: %+v",
49â†’					cc.WantField, cc.WantContains, errs)
50â†’			}
51â†’		})
52â†’	}
53â†’}
